mapper.select:
SELECT symbol AS symbol ,symbol_type AS symbolType ,name AS name ,valid_scale AS validScale ,FORMAT(target_volatility, valid_scale) AS targetVolatility ,sort_order AS sortOrder ,deleted AS deleted ,created_at AS createdAt ,created_by AS createdBy ,updated_at AS updatedAt ,updated_by AS updatedBy FROM fx_symbol WHERE deleted = 0
AND symbol_type = #{symbolType}
ORDER BY sort_order
LIMIT 0, #{size} LIMIT #{offset}, #{size}

SELECT EXISTS
(
    SELECT *
    FROM fx_symbol
    WHERE symbol = #{symbol}
)

mapper.update:
UPDATE fx_symbol
SET
     symbol_type       = #{symbolType}
    ,name              = #{name}
    ,valid_scale       = #{validScale}
    ,target_volatility = #{targetVolatility}
    ,sort_order        = #{sortOrder}
    ,updated_at        = #{updatedAt}
    ,updated_by        = #{updatedBy}
WHERE symbol = #{symbol}

UPDATE fx_symbol
SET
     symbol            = #{symbol.symbol}
    ,symbol_type       = #{symbol.symbolType}
    ,name              = #{symbol.name}
    ,valid_scale       = #{symbol.validScale}
    ,target_volatility = #{symbol.targetVolatility}
    ,sort_order        = #{symbol.sortOrder}
    ,updated_at        = #{symbol.updatedAt}
    ,updated_by        = #{symbol.updatedBy}
WHERE symbol = #{baseSymbol}
